// src/cli/output.ts
function lineLabel(startLine, endLine) {
  return startLine === endLine ? `${startLine}` : `${startLine}-${endLine}`;
}
function formatReview(store) {
  const summary = store.summary?.trim() ?? "";
  const comments = Object.values(store.comments);
  if (!summary && comments.length === 0) return null;
  const lines = [];
  lines.push("# Code review feedback");
  lines.push("");
  if (summary) {
    lines.push("## Overall");
    lines.push("");
    lines.push(summary);
    lines.push("");
  }
  if (comments.length > 0) {
    lines.push("## Comments");
    lines.push("");
    const sorted = [...comments].sort((a, b) => {
      if (a.file !== b.file) return a.file < b.file ? -1 : 1;
      if (a.startLine !== b.startLine) return a.startLine - b.startLine;
      return a.endLine - b.endLine;
    });
    for (const c of sorted) {
      lines.push(`### ${c.file}:${lineLabel(c.startLine, c.endLine)}`);
      lines.push("");
      lines.push(c.body.trim());
      lines.push("");
    }
  }
  return lines.join("\n").replace(/\n+$/, "\n");
}

